import 'dart:io'; import 'package:path_provider/path_provider.dart'; class FileUtils { static String formatSize(int bytes) { if (bytes < 1024) return '$bytes B'; if (bytes < 1048576) return '${(bytes/1024).toStringAsFixed(1)} KB'; return '${(bytes/1048576).toStringAsFixed(1)} MB'; } static Future<String> getDownloadsPath() async { final dir = await getApplicationDocumentsDirectory(); final path = '${dir.path}/GooglePro/Downloads'; await Directory(path).create(recursive: true); return path; } static bool isImage(String path) => ['.jpg','.jpeg','.png','.gif','.webp'].any(path.toLowerCase().endsWith); static bool isVideo(String path) => ['.mp4','.mkv','.avi','.mov'].any(path.toLowerCase().endsWith); }